import java.io.BufferedReader;
import java.io.IOException;
import java.io.InputStreamReader;

public class CommandInjectionFixed {

    public static void main(String[] args) {
        try {
            BufferedReader reader = new BufferedReader(new InputStreamReader(System.in));
            System.out.print("Enter the file name to display: ");
            String fileName = reader.readLine();

            // Validate input to prevent command injection
            if (!fileName.matches("[a-zA-Z0-9_.-]+")) {
                System.out.println("Invalid file name. Please enter a valid file name.");
                return;
            }

            ProcessBuilder processBuilder = new ProcessBuilder("/bin/cat", fileName); // Use absolute path to cat command
            Process process = processBuilder.start();

            BufferedReader processOutputReader = new BufferedReader(new InputStreamReader(process.getInputStream()));
            String line;
            while ((line = processOutputReader.readLine()) != null) {
                System.out.println(line);
            }

        } catch (IOException e) {
            e.printStackTrace();
        }
    }
}

